import importlib
import types

def _load_module(task_id, model):
    """Load a task module from scripts/solutions/<task_id>/<model>.py."""
    base = os.path.join(os.path.dirname(__file__), '..', 'scripts', 'solutions')
    path = os.path.join(base, task_id, f"{model}.py")
    spec = importlib.util.spec_from_file_location(f"{task_id}_{model}", path)
    mod = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod


